    exports: {
      components: {
        MaterialButton,
        SearchInput,
        AddPassword,
        PasswordsCollection
      },

      state: {
        passwords: [],
        searchTerm: ''
      },

      getPasswords() {
        if (this.state.searchTerm) return this.filter(this.state.passwords, this.state.searchTerm)
        return this.state.passwords
      },

      filter(passwords, searchTerm) {
        return passwords.filter(password => {
          return password.name.includes(searchTerm)
        })
      },

      decryptPassword(password) {
        return ['name', 'username', 'value', 'comment'].reduce((acc, key) => {
          acc[key] = password[key] ? store.decrypt(password[key]) : '';
          return acc
        }, password)
      },

      fetch() {
        store.fetchPasswords()
          .then(passwords => passwords.map(p => this.decryptPassword(p)))
          .then(passwords => {
            this.update({ passwords });
          })
          .catch(console.error);
      },

      onSearch(value) {
        this.update({ searchTerm: value });
      },

      addPassword() {
        store.openModal('add-password');
      },

      onMounted() {
        this.fetch();

        store.on('unlock', () => this.fetch());
        store.on('password:added', () => this.fetch());
        store.on('password:edited', () => this.fetch());
        store.on('password:deleted', () => this.fetch());
      }
    },

